// Solution
class Calculator<T> {
    add(a: T, b: T): T {
        if (typeof a === 'number' && typeof b === 'number') {
            return a + b;
        } else {
            throw new Error('Unsupported operation');
        }
    }

    subtract(a: T, b: T): T {
        if (typeof a === 'number' && typeof b === 'number') {
            return a - b;
        } else {
            throw new Error('Unsupported operation');
        }
    }
}
const calculator = new Calculator<number>();
console.log(calculator.add(5, 4));
console.log(calculator.subtract(10, 2.5));
